+    let phase_mode = safety_to_phase1(mode);
+    let restore =
+        phase1_longjmp_restore(&entry.env, val, phase_mode).map_err(phase1_error_errno)?;
+    let mask_restored = entry.savemask;
+    Ok((restore.return_value, mask_restored))
+}
