+        self._registers[REG_CONTEXT_ID] = context_id;
+        self._registers[REG_GENERATION] = generation;
+        self._registers[REG_OWNER_THREAD] = owner_thread;
+        self._registers[REG_MODE_TAG] = mode_tag(mode);
